diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index bab2c6efd403..0e7575cf023c 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -10480,6 +10480,26 @@ preparePlanForEpilogueVectorLoop(VPlan &Plan, Loop *L,
 }

 bool LoopVectorizePass::processLoop(Loop *L) {
+  // Bail out if any loop-invariant value is defined by an invoke. The
+  // vectorizer cannot handle this, because it cannot clone invoke
+  // instructions.
+  for (BasicBlock *BB : L->getBlocks()) {
+    for (Instruction &I : *BB) {
+      for (Value *U : I.operands()) {
+        if (auto *Instr = dyn_cast<Instruction>(U)) {
+          if (!L->contains(Instr) && isa<InvokeInst>(Instr)) {
+            LLVM_DEBUG(dbgs() << "LV: Found use of invoke " << *Instr
+                              << " from outside the loop. Bailing out.\n");
+            return false;
+          }
+        }
+      }
+    }
+  }
+
+for (BasicBlock *BB : L->getBlocks()) {    if (!isBlockInLCSSA(DT, BB, L)) {      LLVM_DEBUG(dbgs() << "LV: Not in LCSSA form.
+");      return false;    }    for (Instruction &I : *BB)      for (Value *U : I.operands())        if (auto *Instr = dyn_cast<Instruction>(U))          if (!L->contains(Instr) && isa<InvokeInst>(Instr)) {            LLVM_DEBUG(dbgs() << "LV: Found use of invoke " << *Instr                              << " from outside the loop.
+");            return false;          }  }
   assert((EnableVPlanNativePath || L->isInnermost()) &&
          "VPlan-native path is not enabled. Only process inner loops.");

